// Cloudflare Worker - Playlist Server (Secure Version)
// Deploy: wrangler deploy

// Secret keys - set via: wrangler secret put ADMIN_API_KEY
// Default for demo (CHANGE IN PRODUCTION!)
const DEFAULT_ADMIN_KEY = "app-admin-2024-secure";
const APP_SECRET = "app-secret-key-change-me";

// Simple hash function for token verification
async function hashMessage(message) {
  const encoder = new TextEncoder();
  const data = encoder.encode(message);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// Generate time-based token
function generateToken(secret, timestamp) {
  const hour = Math.floor(timestamp / 3600000);
  return hashMessage(`${secret}:${hour}`);
}

// Verify app token
async function verifyAppToken(token, secret) {
  const now = Date.now();
  // Check current hour and previous hour (for clock drift)
  const currentToken = await hashMessage(`${secret}:${Math.floor(now / 3600000)}`);
  const prevToken = await hashMessage(`${secret}:${Math.floor(now / 3600000) - 1}`);
  return token === currentToken || token === prevToken;
}

// Verify admin - check session cookie OR Bearer token
async function verifyAdmin(request, env) {
  const adminKey = env.ADMIN_API_KEY || DEFAULT_ADMIN_KEY;
  
  // Check session cookie first
  const cookies = request.headers.get('Cookie') || '';
  const sessionMatch = cookies.match(/admin_session=([^;]+)/);
  if (sessionMatch) {
    const sessionToken = sessionMatch[1];
    const validSession = await hashMessage(`${adminKey}:${Math.floor(Date.now() / 86400000)}`);
    if (sessionToken === validSession) {
      return true;
    }
  }
  
  // Fallback to Bearer token (for API clients)
  const authHeader = request.headers.get('Authorization');
  if (authHeader && authHeader === `Bearer ${adminKey}`) {
    return true;
  }
  
  return false;
}

// Simple rate limiting
const rateLimitMap = new Map();

function checkRateLimit(ip, limit = 100, windowMs = 60000) {
  const now = Date.now();
  const key = ip;
  
  if (!rateLimitMap.has(key)) {
    rateLimitMap.set(key, { count: 1, resetTime: now + windowMs });
    return true;
  }
  
  const record = rateLimitMap.get(key);
  if (now > record.resetTime) {
    record.count = 1;
    record.resetTime = now + windowMs;
    return true;
  }
  
  if (record.count >= limit) {
    return false;
  }
  
  record.count++;
  return true;
}

// Obfuscate URL (simple encoding)
function obfuscateUrl(url) {
  return btoa(url);
}

function deobfuscateUrl(encoded) {
  try {
    return atob(encoded);
  } catch {
    return null;
  }
}

