export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
    
    // Rate limiting
    if (!checkRateLimit(clientIP, 200, 60000)) {
      return new Response(JSON.stringify({ error: 'Rate limit exceeded' }), {
        status: 429,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    // CORS headers
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-App-Token',
    };

    if (request.method === 'OPTIONS') {
      return new Response(null, { headers: corsHeaders });
    }

    // === PUBLIC ENDPOINTS (no auth required) ===
    
    // Get app token (for app to authenticate)
    if (url.pathname === '/api/token') {
      const token = await generateToken(APP_SECRET, Date.now());
      return new Response(JSON.stringify({ token, expiresIn: 3600 }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    // === APP ENDPOINTS (token required) ===
    
    // Get playlist
    if (url.pathname === '/api/playlist') {
      return this.handleGetPlaylist(env, corsHeaders);
    }
    
    // Get channels
    if (url.pathname === '/api/channels') {
      return this.handleGetChannels(env, corsHeaders);
    }

    // === ADMIN ENDPOINTS (session cookie or API key required) ===
    
    if (url.pathname.startsWith('/api/admin')) {
      if (!await verifyAdmin(request, env)) {
        return new Response(JSON.stringify({ error: 'Unauthorized' }), {
          status: 401,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }

      if (url.pathname === '/api/admin/channels' && request.method === 'GET') {
        return this.handleAdminGetChannels(env, corsHeaders);
      }

      if (url.pathname === '/api/admin/channels' && request.method === 'POST') {
        return this.handleAdminAddChannel(request, env, corsHeaders);
      }

      if (url.pathname.startsWith('/api/admin/channels/') && request.method === 'PUT') {
        const id = url.pathname.split('/').pop();
        return this.handleAdminUpdateChannel(id, request, env, corsHeaders);
      }

      if (url.pathname.startsWith('/api/admin/channels/') && request.method === 'DELETE') {
        const id = url.pathname.split('/').pop();
        return this.handleAdminDeleteChannel(id, env, corsHeaders);
      }
    }

    if (url.pathname === '/playlist.m3u') {
      return this.handleM3UFormat(env, corsHeaders);
    }

    // === ADMIN PANEL (session-based auth) ===
    
    // Admin login endpoint - verify password and set session cookie
    if (url.pathname === '/admin/login' && request.method === 'POST') {
      try {
        const body = await request.json();
        const password = body.password;
        const adminKey = env.ADMIN_API_KEY || DEFAULT_ADMIN_KEY;
        
        if (password === adminKey) {
          // Generate session token (valid for 24 hours)
          const sessionToken = await hashMessage(`${adminKey}:${Math.floor(Date.now() / 86400000)}`);
          
          return new Response(JSON.stringify({ success: true }), {
            headers: {
              ...corsHeaders,
              'Content-Type': 'application/json',
              'Set-Cookie': `admin_session=${sessionToken}; Path=/admin; HttpOnly; SameSite=Strict; Max-Age=86400`
            }
          });
        }
        
        return new Response(JSON.stringify({ error: 'Invalid password' }), {
          status: 401,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      } catch (e) {
        return new Response(JSON.stringify({ error: 'Invalid request' }), {
          status: 400,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }
    }
    
    // Admin logout
    if (url.pathname === '/admin/logout' && request.method === 'POST') {
      return new Response(JSON.stringify({ success: true }), {
        headers: {
          ...corsHeaders,
          'Content-Type': 'application/json',
          'Set-Cookie': 'admin_session=; Path=/admin; HttpOnly; SameSite=Strict; Max-Age=0'
        }
      });
    }
    
    // Admin panel - check session cookie
    if (url.pathname === '/admin' || url.pathname === '/admin/') {
      const cookies = request.headers.get('Cookie') || '';
      const sessionMatch = cookies.match(/admin_session=([^;]+)/);
      const sessionToken = sessionMatch ? sessionMatch[1] : null;
      
      const adminKey = env.ADMIN_API_KEY || DEFAULT_ADMIN_KEY;
      const validSession = await hashMessage(`${adminKey}:${Math.floor(Date.now() / 86400000)}`);
      
      if (sessionToken && sessionToken === validSession) {
        return this.handleAdminPanel(corsHeaders);
      }
      
      return this.handleAdminLogin(corsHeaders);
    }

    // Default: 404
    return new Response(JSON.stringify({ error: 'Not found' }), {
      status: 404,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  },

  async handleGetPlaylist(env, corsHeaders) {
    const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
    
    let m3uString = "#EXTM3U\r\n";
    playlist.channels.forEach(ch => {
      m3uString += `#EXTINF:-1 group-title="${ch.group}",${ch.name}\r\n${ch.url}\r\n`;
    });

    return new Response(m3uString, {
      headers: { ...corsHeaders, 'Content-Type': 'text/plain; charset=utf-8' }
    });
  },

  async handleGetChannels(env, corsHeaders) {
    const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
    const channels = playlist.channels.map((ch, idx) => ({
      id: idx,
      name: ch.name,
      group: ch.group,
      url: obfuscateUrl(ch.url)
    }));
    return new Response(JSON.stringify(channels), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  },

  async handleAdminGetChannels(env, corsHeaders) {
    const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
    return new Response(JSON.stringify({
      ...playlist,
      channels: playlist.channels.map((ch, idx) => ({ ...ch, id: idx }))
    }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  },

  async handleAdminAddChannel(request, env, corsHeaders) {
    try {
      const newChannel = await request.json();
      const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
      
      // Validate URL
      try {
        new URL(newChannel.url);
      } catch {
        return new Response(JSON.stringify({ error: 'Invalid URL' }), {
          status: 400,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }
      
      playlist.channels.push({
        name: newChannel.name,
        group: newChannel.group,
        url: newChannel.url
      });
      await env.PLAYLIST?.put('playlist', JSON.stringify(playlist));
      
      return new Response(JSON.stringify({ success: true, count: playlist.channels.length }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    } catch (e) {
      return new Response(JSON.stringify({ error: e.message }), {
        status: 400,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }
  },

  async handleAdminUpdateChannel(id, request, env, corsHeaders) {
    try {
      const updatedChannel = await request.json();
      const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
      const index = parseInt(id);
      
      if (index >= 0 && index < playlist.channels.length) {
        playlist.channels[index] = {
          name: updatedChannel.name,
          group: updatedChannel.group,
          url: updatedChannel.url
        };
        await env.PLAYLIST?.put('playlist', JSON.stringify(playlist));
        
        return new Response(JSON.stringify({ success: true }), {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }
      
      return new Response(JSON.stringify({ error: 'Channel not found' }), {
        status: 404,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    } catch (e) {
      return new Response(JSON.stringify({ error: e.message }), {
        status: 400,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }
  },

  async handleAdminDeleteChannel(id, env, corsHeaders) {
    const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
    const index = parseInt(id);
    
    if (index >= 0 && index < playlist.channels.length) {
      playlist.channels.splice(index, 1);
      await env.PLAYLIST?.put('playlist', JSON.stringify(playlist));
      
      return new Response(JSON.stringify({ success: true, count: playlist.channels.length }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }
    
    return new Response(JSON.stringify({ error: 'Channel not found' }), {
      status: 404,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  },

  async handleM3UFormat(env, corsHeaders) {
    const playlist = await env.PLAYLIST?.get('playlist', 'json') || DEFAULT_PLAYLIST;
    
    let m3u = '#EXTM3U\n';
    for (const ch of playlist.channels) {
      m3u += `#EXTINF:-1 tvg-name="${ch.name}" group-title="${ch.group}",${ch.name}\n`;
      m3u += `${ch.url}\n`;
    }
    
    return new Response(m3u, {
      headers: {
        ...corsHeaders,
        'Content-Type': 'audio/x-mpegurl',
        'Content-Disposition': `attachment; filename="${playlist.name}.m3u"`
      }
    });
  },

  async handleAdminLogin(corsHeaders) {
    const html = `<!DOCTYPE html>
<html lang="vi">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Admin - Login</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { 
            font-family: -apple-system, sans-serif; 
            background: linear-gradient(135deg, #1a1a2e, #16213e); 
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .login-box {
            background: rgba(255,255,255,0.1);
            padding: 40px;
            border-radius: 16px;
            backdrop-filter: blur(10px);
            width: 100%;
            max-width: 400px;
        }
        h1 { color: #ffd700; margin-bottom: 24px; text-align: center; }
        input {
            width: 100%;
            padding: 14px;
            border: 1px solid rgba(255,255,255,0.2);
            border-radius: 8px;
            background: rgba(255,255,255,0.05);
            color: #fff;
            font-size: 16px;
            margin-bottom: 16px;
        }
        input:focus { outline: none; border-color: #ffd700; }
        button {
            width: 100%;
            padding: 14px;
            background: #ffd700;
            color: #1a1a2e;
            border: none;
            border-radius: 8px;
            font-size: 16px;
            font-weight: 600;
            cursor: pointer;
        }
        button:hover { background: #ffe44d; }
        .error { color: #e53935; text-align: center; margin-top: 12px; }
    </style>
</head>
<body>
    <div class="login-box">
        <h1>🔒 Admin Login</h1>
        <form id="loginForm">
            <input type="password" id="password" placeholder="Nhập mật khẩu" required>
            <button type="submit">Đăng nhập</button>
        </form>
        <div id="error" class="error" style="display:none"></div>
    </div>
    <script>
        document.getElementById('loginForm').addEventListener('submit', async (e) => {
            e.preventDefault();
            const pw = document.getElementById('password').value;
            const errorEl = document.getElementById('error');
            
            try {
                const res = await fetch('/admin/login', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ password: pw })
                });
                
                const data = await res.json();
                
                if (data.success) {
                    // Login successful, redirect to admin panel
                    window.location.href = '/admin';
                } else {
                    errorEl.textContent = 'Sai mật khẩu';
                    errorEl.style.display = 'block';
                }
            } catch (err) {
                errorEl.textContent = 'Lỗi kết nối';
                errorEl.style.display = 'block';
            }
        });
    </script>
</body>
</html>`;
    
    return new Response(html, {
      headers: { ...corsHeaders, 'Content-Type': 'text/html; charset=utf-8' }
    });
  },

  async handleAdminPanel(corsHeaders) {
    const html = `<!DOCTYPE html>
<html lang="vi">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Admin Panel</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: -apple-system, sans-serif; background: #1a1a2e; color: #fff; padding: 20px; }
        .container { max-width: 1200px; margin: 0 auto; }
        .header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
        h1 { color: #ffd700; }
        .btn { padding: 10px 20px; border: none; border-radius: 8px; cursor: pointer; font-weight: 500; }
        .btn-primary { background: #ffd700; color: #1a1a2e; }
        .btn-danger { background: #e53935; color: #fff; }
        .btn-logout { background: #666; color: #fff; }
        .card { background: rgba(255,255,255,0.1); border-radius: 12px; padding: 20px; margin-bottom: 20px; }
        .form-group { margin-bottom: 15px; }
        label { display: block; margin-bottom: 5px; color: #b0b0b0; }
        input { width: 100%; padding: 10px; border: 1px solid rgba(255,255,255,0.2); border-radius: 8px; background: rgba(255,255,255,0.05); color: #fff; }
        input:focus { outline: none; border-color: #ffd700; }
        .channel-item { display: flex; align-items: center; padding: 10px; border-bottom: 1px solid rgba(255,255,255,0.1); gap: 10px; }
        .channel-name { flex: 1; }
        .channel-group { color: #ffd700; }
        .channel-url { flex: 2; color: #888; font-size: 12px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
        .status { padding: 5px 10px; border-radius: 4px; font-size: 12px; }
        .status.success { background: #4caf50; }
        .status.error { background: #e53935; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>📺 Admin Panel</h1>
            <button class="btn btn-logout" onclick="logout()">Đăng xuất</button>
        </div>
        <div class="card">
            <h2>Thêm kênh mới</h2>
            <div class="form-group">
                <label>Tên kênh</label>
                <input type="text" id="channelName" placeholder="VTV1 FHD">
            </div>
            <div class="form-group">
                <label>Nhóm</label>
                <input type="text" id="channelGroup" placeholder="FPT [ALT]">
            </div>
            <div class="form-group">
                <label>URL Stream</label>
                <input type="text" id="channelUrl" placeholder="https://...">
            </div>
            <button class="btn btn-primary" onclick="addChannel()">Thêm kênh</button>
            <span id="addStatus"></span>
        </div>
        <div class="card">
            <h2>Danh sách kênh (<span id="channelCount">0</span>)</h2>
            <div id="channelsList"></div>
        </div>
    </div>
    <script>
        const API = window.location.origin;
        let channels = [];

        // Session cookie is sent automatically with fetch (credentials: 'same-origin')
        async function apiCall(path, method = 'GET', body = null) {
            const headers = {};
            if (body) headers['Content-Type'] = 'application/json';
            const res = await fetch(API + path, { 
                method, 
                headers, 
                body: body ? JSON.stringify(body) : null,
                credentials: 'same-origin'
            });
            
            // If unauthorized, redirect to login
            if (res.status === 401) {
                window.location.href = '/admin';
                return null;
            }
            
            return res.json();
        }

        async function logout() {
            await fetch(API + '/admin/logout', { method: 'POST', credentials: 'same-origin' });
            window.location.href = '/admin';
        }

        async function loadChannels() {
            const data = await apiCall('/api/admin/channels');
            if (!data) return;
            channels = data.channels || [];
            document.getElementById('channelCount').textContent = channels.length;
            document.getElementById('channelsList').innerHTML = channels.map((ch, i) => \`
                <div class="channel-item">
                    <span class="channel-name">\${ch.name}</span>
                    <span class="channel-group">\${ch.group}</span>
                    <span class="channel-url" title="\${ch.url}">\${ch.url}</span>
                    <button class="btn btn-danger" onclick="deleteChannel(\${i})">Xóa</button>
                </div>
            \`).join('');
        }

        async function addChannel() {
            const name = document.getElementById('channelName').value;
            const group = document.getElementById('channelGroup').value;
            const url = document.getElementById('channelUrl').value;
            if (!name || !group || !url) { showStatus('addStatus', 'Nhập đầy đủ', false); return; }
            const data = await apiCall('/api/admin/channels', 'POST', { name, group, url });
            if (data && data.success) { loadChannels(); showStatus('addStatus', 'Đã thêm!', true); }
        }

        async function deleteChannel(i) {
            if (!confirm('Xóa?')) return;
            await apiCall('/api/admin/channels/' + i, 'DELETE');
            loadChannels();
        }

        function showStatus(id, msg, ok) {
            const el = document.getElementById(id);
            el.textContent = msg;
            el.className = 'status ' + (ok ? 'success' : 'error');
        }

        loadChannels();
    </script>
</body>
</html>`;
    
    return new Response(html, {
      headers: { ...corsHeaders, 'Content-Type': 'text/html; charset=utf-8' }
    });
  }
};
